#include <stdio.h>
#include <stdint.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        unsigned long long n;
        scanf("%llu", &n);
        int msb = 0;
        unsigned long long tmp = n;
        while (tmp > 1) {
            tmp >>= 1;
            msb++;
        }
        unsigned long long result = n ^ 1ULL ^ (1ULL << msb);
        printf("%llu\n", result);
    }
    return 0;
}

